import outlines
from outlines.prompts import register_filter, unregister_filter

register_filter('shout', lambda s: s.upper() + '!')

@outlines.prompt
def greet(name):
    '''{{ name | shout }}'''

print(greet('world'))

unregister_filter('shout')

@outlines.prompt
def greet2(name):
    '''{{ name | shout }}'''

try:
    greet2('world')
    print('ERROR: should have raised')
except Exception as e:
    print('correctly raised:', type(e).__name__)

# test local (builtin) precedence: registering a filter named 'name' should not override builtin get_fn_name
register_filter('name', lambda s: 'HIJACKED')

def foo():
    pass

@outlines.prompt
def name_test(fn):
    '''{{ fn | name }}'''

print(name_test(foo))
unregister_filter('name')
"

